window.marked={parse:function(input){function e(s){return String(s??"").replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#039;")}function i(s){return e(s).replace(/\*\*([^*]+)\*\*/g,"<strong>$1</strong>").replace(/`([^`]+)`/g,"<code>$1</code>")}const lines=String(input??"").replace(/\r\n/g,"\n").split("\n");let html=[],para=[],list=[];function flushPara(){if(para.length){html.push("<p>"+i(para.join(" "))+"</p>");para=[]}}function flushList(){if(list.length){html.push("<ul>"+list.map(x=>"<li>"+i(x)+"</li>").join("")+"</ul>");list=[]}}for(const raw of lines){const line=raw.trim();if(!line){flushPara();flushList();continue}const h=line.match(/^(#{1,6})\s+(.+)$/);if(h){flushPara();flushList();const level=Math.min(h[1].length,6);html.push("<h"+level+">"+i(h[2])+"</h"+level+">");continue}const ordered=line.match(/^\d+\.\s+(.+)$/);if(ordered){flushPara();list.push(ordered[1]);continue}const bullet=line.match(/^[-*]\s+(.+)$/);if(bullet){flushPara();list.push(bullet[1]);continue}flushList();para.push(line)}flushPara();flushList();return html.join("")}};
